#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MAX_N 100000
#define MAX_M 1000000
// Function to check if a number is a cubic number
int is_cubic(int num) {
    int cube_root = (int)round(cbrt(num));
    return cube_root * cube_root * cube_root == num;
}
// Function to perform DFS
void dfs(int node, int parent, int product, int *values, int **edges, int *edges_count, int *answer) {
    product *= values[node];
    if (is_cubic(product)) {
        *answer = (*answer > edges_count[node] ? *answer : edges_count[node]);
    }
    for (int i = 0; i < edges_count[node]; i++) {
        int child = edges[node][i];
        if (child != parent) {
            dfs(child, node, product, values, edges, edges_count, answer);
        }
    }
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int *values = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &values[i]);
        }
        int **edges = (int **)malloc(N * sizeof(int *));
        int *edges_count = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            edges[i] = (int *)malloc(N * sizeof(int));
            edges_count[i] = 0;
        }
        for (int i = 0; i < N - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--;
            v--;
            edges[u][edges_count[u]++] = v;
            edges[v][edges_count[v]++] = u;
        }
        int answer = -1;
        dfs(0, -1, 1, values, edges, edges_count, &answer);
        printf("%d\n", answer);
        for (int i = 0; i < N; i++) {
            free(edges[i]);
        }
        free(edges);
        free(edges_count);
        free(values);
    }
    return 0;
}

