#include <iostream>
#include <vector>
#include <cmath>
using namespace std;
// Function to check if a number is a cubic number
bool is_cubic(int num) {
    int cube_root = round(cbrt(num));
    return cube_root * cube_root * cube_root == num;
}
// Function to perform DFS
void dfs(int node, int parent, int product, vector<int> &values, vector<vector<int>> &edges, int &answer) {
    product *= values[node];
    if (is_cubic(product)) {
        answer = max(answer, (int)edges[node].size());
    }
    for (int child : edges[node]) {
        if (child != parent) {
            dfs(child, node, product, values, edges, answer);
        }
    }
}
int main() {
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        vector<int> values(N);
        for (int i = 0; i < N; i++) {
            cin >> values[i];
        }
        vector<vector<int>> edges(N);
        for (int i = 0; i < N - 1; i++) {
            int u, v;
            cin >> u >> v;
            u--;
            v--;
            edges[u].push_back(v);
            edges[v].push_back(u);
        }
        int answer = -1;
        dfs(0, -1, 1, values, edges, answer);
        cout << answer << endl;
    }
    return 0;
}

