import java.util.Scanner;
public class Main {
    // Function to check if a number is a cubic number
    public static boolean is_cubic(int num) {
        int cube_root = (int) Math.round(Math.cbrt(num));
        return cube_root * cube_root * cube_root == num;
    }
    // Function to perform DFS
    public static void dfs(int node, int parent, int product, int[] values, int[][] edges, int[] edges_count, int[] answer) {
        product *= values[node];
        if (is_cubic(product)) {
            answer[0] = Math.max(answer[0], edges_count[node]);
        }
        for (int i = 0; i < edges_count[node]; i++) {
            int child = edges[node][i];
            if (child != parent) {
                dfs(child, node, product, values, edges, edges_count, answer);
            }
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] values = new int[N];
            for (int i = 0; i < N; i++) {
                values[i] = scanner.nextInt();
            }
            int[][] edges = new int[N][];
            int[] edges_count = new int[N];
            for (int i = 0; i < N; i++) {
                edges[i] = new int[N];
            }
            for (int i = 0; i < N - 1; i++) {
                int u = scanner.nextInt() - 1;
                int v = scanner.nextInt() - 1;
                edges[u][edges_count[u]++] = v;
                edges[v][edges_count[v]++] = u;
            }
            int[] answer = new int[] {-1};
            dfs(0, -1, 1, values, edges, edges_count, answer);
            System.out.println(answer[0]);
        }
    }
}

